Here is a clean, unobfuscated implementation of the A* (A-star) pathfinding algorithm based on the logic in the provided code. 

The original code sets up a 2D grid with randomly generated obstacles, defines a start and end point, and uses the A* algorithm with either Manhattan or Euclidean heuristics to find the shortest path. I've renamed the variables and functions to standard, readable conventions and formatted the logic cleanly.

```javascript
// --- Configuration & Initialization ---
const gridWidth = 20;
const gridHeight = 15;

const config = {
    penalty: 'manhattan',   // Heuristic strategy ('manhattan' or euclidean distance)
    adjacentCost: 1.414,    // Cost for moving diagonally (approx sqrt(2))
    traversalCost: 1,       // Cost for moving orthogonally (up/down/left/right)
    maxIterations: 1000,    // Safety limit to prevent infinite loops (called minIterations in obfuscated code)
    clearanceRatio: 0.25    // 25% chance of a grid tile being an obstacle
};

// Generate the grid
const grid = [];
for (let y = 0; y < gridHeight; y++) {
    grid[y] = [];
    for (let x = 0; x < gridWidth; x++) {
        // 1 = Obstacle, 0 = Walkable
        grid[y][x] = Math.random() < config.clearanceRatio ? 1 : 0;
    }
}

// Define Start and End coordinates
const startNode = { x: 0, y: 0 };
const endNode = { x: gridWidth - 1, y: gridHeight - 1 };

// Guarantee that start and end nodes are always walkable
grid[startNode.y][startNode.x] = 0;
grid[endNode.y][endNode.x] = 0;


// --- Helper Functions ---

// Generates a unique string key for a coordinate (e.g., "5,10")
function getNodeKey(node) {
    return `${node.x},${node.y}`;
}

// Estimates the distance from a given node to the target
function getHeuristic(node, target) {
    const dx = Math.abs(node.x - target.x);
    const dy = Math.abs(node.y - target.y);

    if (config.penalty === 'manhattan') {
        return dx + dy;
    }
    // Fallback to Euclidean distance
    return Math.sqrt(dx * dx + dy * dy);
}

// Retrieves all valid, walkable neighboring nodes
function getNeighbors(node) {
    const neighbors = [];
    const directions = [
        { dx: 0, dy: -1, cost: config.traversalCost },  // Up
        { dx: 0, dy: 1, cost: config.traversalCost },   // Down
        { dx: -1, dy: 0, cost: config.traversalCost },  // Left
        { dx: 1, dy: 0, cost: config.traversalCost },   // Right
        { dx: -1, dy: -1, cost: config.adjacentCost },  // Top-Left
        { dx: 1, dy: -1, cost: config.adjacentCost },   // Top-Right
        { dx: -1, dy: 1, cost: config.adjacentCost },   // Bottom-Left
        { dx: 1, dy: 1, cost: config.adjacentCost }     // Bottom-Right
    ];

    for (const dir of directions) {
        const nx = node.x + dir.dx;
        const ny = node.y + dir.dy;

        // Check grid bounds and ensure the tile is walkable (0)
        if (nx >= 0 && nx < gridWidth && ny >= 0 && ny < gridHeight && grid[ny][nx] === 0) {
            neighbors.push({
                x: nx,
                y: ny,
                moveCost: dir.cost
            });
        }
    }
    return neighbors;
}


// --- Main A* Pathfinding Logic ---

function findPath(start, end) {
    const startKey = getNodeKey(start);

    const openSet = {};   // Nodes to be evaluated
    const closedSet = {}; // Nodes already evaluated
    const gScore = {};    // Cost from start along best known path
    const fScore = {};    // Estimated total cost from start to goal
    const cameFrom = {};  // To reconstruct the path

    let iterations = 0;

    // Initialize with start node
    openSet[startKey] = start;
    gScore[startKey] = 0;
    fScore[startKey] = getHeuristic(start, end);

    while (Object.keys(openSet).length > 0 && iterations < config.maxIterations) {
        iterations++;

        // Find the node in openSet with the lowest fScore
        let currentKey = null;
        let lowestFScore = Infinity;

        for (const key in openSet) {
            if (fScore[key] < lowestFScore) {
                lowestFScore = fScore[key];
                currentKey = key;
            }
        }

        const current = openSet[currentKey];

        // If we reached the destination
        if (current.x === end.x && current.y === end.y) {
            const path = [current];
            let currKey = currentKey;

            // Reconstruct the path working backwards
            while (cameFrom[currKey]) {
                currKey = cameFrom[currKey];
                const nodeData = openSet[currKey] || closedSet[currKey] || {
                    x: parseInt(currKey.split(',')[0], 10),
                    y: parseInt(currKey.split(',')[1], 10)
                };
                path.unshift(nodeData); // Push to front to make the final path Start -> End
            }

            return {
                path: path,
                cost: gScore[currentKey],
                iterations: iterations
            };
        }

        // Move current node from open to closed set
        delete openSet[currentKey];
        closedSet[currentKey] = current;

        // Evaluate all neighboring nodes
        const neighbors = getNeighbors(current);

        for (const neighbor of neighbors) {
            const nKey = getNodeKey(neighbor);

            if (closedSet[nKey]) continue; // Ignore previously evaluated nodes

            const tentativeGScore = gScore[currentKey] + neighbor.moveCost;

            // If we discovered a new or shorter path to this neighbor
            if (gScore[nKey] === undefined || tentativeGScore < gScore[nKey]) {
                cameFrom[nKey] = currentKey;
                gScore[nKey] = tentativeGScore;
                fScore[nKey] = tentativeGScore + getHeuristic(neighbor, end);
                openSet[nKey] = neighbor;
            }
        }
    }

    // Return empty state if no path is found
    return {
        path: [],
        cost: Infinity,
        iterations: iterations
    };
}

// --- Execution ---

const result = findPath(startNode, endNode);
console.log('Path length:', result.path.length, 'Cost:', result.cost, 'Iterations:', result.iterations);
